  ('social-worker-moex-03748', 'social-worker', 'social-worker-moex-113-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據國民年金法規定，關於請領身心障礙年金給付之敘述，下列何者正確？', '["經評估有工作能力的人士，被保險期間內罹患疾病經治療終止，症狀固定", "被保險人遭受傷害或罹患疾病，症狀固定且再行治療無效，並經評估有工作能力", "被保險人於保險期間遭受重傷或罹患嚴重疾病，經治療一年以上尚未痊癒，且無工作能力", "被保險人於保險期間遭受輕傷或罹患輕微疾病，經治療後已完全康復"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:21+00:00", "source_pdf_sha1": "1c2dd3206437", "answer_pdf_sha1": "011a70151cb0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
